var SpinnerProgressTracker = class {
  spinner = null;
  start(message) {
    this.spinner = createSpinner(message);
    this.spinner.start();
  }
  update(message) {
    if (this.spinner) {
      this.spinner.text = message;
    }
  }
  succeed(message) {
    if (this.spinner) {
      this.spinner.succeed(message);
      this.spinner = null;
    }
  }
  fail(message) {
    if (this.spinner) {
      this.spinner.fail(message);
      this.spinner = null;
    }
  }
  warn(message) {
    if (this.spinner) {
      this.spinner.warn(message);
      this.spinner = null;
    }
  }
};
